import React, { useEffect, useRef } from 'react';

export const AgentSelector = () => {
  const agentElementRef = useRef<HTMLElement | null>(null);

  useEffect(() => {
    const findAndSelectAgent = () => {
      const agentContainer = document.querySelector('.embedded-agent-container') as HTMLElement;
      
      if (agentContainer) {
        // Agent found - you can add any logic here
        console.log('AI Agent container found:', agentContainer);
        agentElementRef.current = agentContainer;
      } else {
        // Retry after a short delay if not found immediately
        setTimeout(findAndSelectAgent, 100);
      }
    };

    findAndSelectAgent();
  }, []);

  return (
    <button
      className="fixed bottom-[124px] right-[8px] sm:right-[16px] w-10 h-10 bg-red-600 hover:bg-red-700 border-2 border-white rounded flex items-center justify-center transition-colors z-[9999]"
      aria-label="Close AI agent"
    >
      <svg
        xmlns="http://www.w3.org/2000/svg"
        className="h-6 w-6 text-white"
        fill="none"
        viewBox="0 0 24 24"
        stroke="currentColor"
        strokeWidth={2}
      >
        <path
          strokeLinecap="round"
          strokeLinejoin="round"
          d="M6 18L18 6M6 6l12 12"
        />
      </svg>
    </button>
  );
};

export default AgentSelector;
